-- Cached flat array of all atlas names
local allAtlasesCache = nil

function TAD:GetCategories()
    return CATEGORIES
end

function TAD:GetAtlases(categoryId)
    return ATLAS_DATA[categoryId] or {}
end

function TAD:GetAllAtlases()
    if allAtlasesCache then return allAtlasesCache end
    allAtlasesCache = {}
    for _, cat in ipairs(CATEGORIES) do
        local atlases = ATLAS_DATA[cat.id]
        if atlases then
            for _, name in ipairs(atlases) do
                allAtlasesCache[#allAtlasesCache + 1] = name
            end
        end
    end
    return allAtlasesCache
end
